function universalClean(rawText) {
    if (!rawText || typeof rawText !== 'string') return "";

    const linkDumpMarkers = [/\nLinks\/Buttons:/i, /\nReferences:/i, /\nLinks List:/i];
    let cleanedContent = rawText;
    for (let marker of linkDumpMarkers) {
        const split = cleanedContent.split(marker);
        if (split.length > 1) {
            cleanedContent = split[0]; // Throw away everything after the dump starts
        }
    }

    const lines = cleanedContent.split('\n');
    const result = [];

    // 2. UNIVERSAL NOISE PATTERNS
    const globalBoilerplate = /privacy|terms|cookie|sitemap|copyright|rights reserved|contact us|follow us|subscribe|newsletter|skip to/i;
    const socialMedia = /facebook\.com|twitter\.com|x\.com|linkedin\.com|instagram\.com|youtube\.com/i;

    for (let line of lines) {
        const trimmed = line.trim();
        if (trimmed.length < 4) continue; // Skip tiny fragments

        // 3. DATE PROTECTION (The "News Anchor")
        // If a line looks like a date (contains a year 202X or a Month name), 
        // we are very careful about deleting it.
        const hasYear = /\b20\d{2}\b/.test(trimmed);
        const hasMonth = /\b(Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)\b/i.test(trimmed);
        const isDate = hasYear || hasMonth;

        // 4. LINK DENSITY CALCULATION
        // We count how many characters in the line are inside a Markdown link [text](url)
        const linkMatches = trimmed.match(/\[.*?\]\(.*?\)/g) || [];
        const linkChars = linkMatches.reduce((acc, link) => acc + link.length, 0);
        const density = linkChars / trimmed.length;

        // --- FILTERING LOGIC ---

        // A. Filter Social Media (Universal noise)
        if (socialMedia.test(trimmed)) continue;

        // B. Filter Boilerplate (Universal footer/header noise)
        // Only filter if it's a short line (actual articles might mention "Privacy" in a long sentence)
        if (globalBoilerplate.test(trimmed) && trimmed.length < 150) continue;

        // C. Filter Menu Bars (Universal Pattern)
        // If > 70% of the line is just links, and it's not a Date line, it's almost certainly a menu.
        if (density > 0.70 && !isDate && trimmed.length < 300) {
            continue;
        }

        // D. Filter Image-only lines (Unless they are part of news)
        if (trimmed.startsWith('![') && !isDate && trimmed.length < 100) continue;

        result.push(trimmed);
    }

    // Join and collapse excessive newlines
    return result.join('\n').replace(/\n{3,}/g, '\n\n');
}

// n8n Input Mapping
return $input.all().map(item => {
    // This auto-detects if your field is "data", "markdown", or "text"
    const rawContent = item.json.data || item.json.markdown || item.json.text || ""; 

    return {
        json: {
            ...item.json, 
            cleaned_content: universalClean(rawContent)
        }
    };
});
